import{_ as a,o as t,c as o,a2 as r}from"./chunks/framework.BFZItJIV.js";const u=JSON.parse('{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority.","frontmatter":{"title":"Roadmap","description":"Planned and in-progress features for TalaDB — ordered by impact and priority."},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md"}'),n={name:"roadmap.md"};function i(s,e,d,c,l,h){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#roadmap" aria-label="Permalink to &quot;Roadmap&quot;">​</a></h1><p>This page tracks planned and in-progress work for TalaDB. Sections and items are ordered by estimated impact — things at the top affect the most users and unblock the most use cases.</p><p>Have an idea or want to help prioritise? Open a <a href="https://github.com/thinkgrid-labs/taladb/discussions" target="_blank" rel="noreferrer">GitHub Discussion</a> or a feature request issue.</p><hr><h2 id="_1-·-developer-experience" tabindex="-1">1 · Developer experience <a class="header-anchor" href="#_1-·-developer-experience" aria-label="Permalink to &quot;1 · Developer experience&quot;">​</a></h2><p>Better DX drives adoption and reduces time-to-production.</p><h3 id="sync" tabindex="-1">Sync <a class="header-anchor" href="#sync" aria-label="Permalink to &quot;Sync&quot;">​</a></h3><ul><li>Native NoSQL adapters (<code>sync.adapter: mongodb | firestore | dynamodb</code>) with direct connection strings, removing the need for an intermediate API</li><li>Bi-directional pull: <code>taladb sync --pull</code> fetches from the remote and merges locally</li><li>Per-collection sync config (sync some collections, skip others)</li></ul><h3 id="aggregation-api" tabindex="-1">Aggregation API <a class="header-anchor" href="#aggregation-api" aria-label="Permalink to &quot;Aggregation API&quot;">​</a></h3><p>A pipeline-style aggregation API for computing summaries inside the engine without materialising every document in JavaScript:</p><ul><li><code>collection.aggregate([{ $group: { _id: &#39;$status&#39;, count: { $sum: 1 } } }])</code></li><li>Supported stages (v1): <code>$match</code>, <code>$group</code>, <code>$sort</code>, <code>$limit</code>, <code>$project</code></li><li>Group accumulators: <code>$sum</code>, <code>$count</code>, <code>$avg</code>, <code>$min</code>, <code>$max</code></li><li>Runs as a single pass over the B-tree / index; result never fully materialised in Rust heap for large collections</li></ul><h3 id="compound-indexes" tabindex="-1">Compound indexes <a class="header-anchor" href="#compound-indexes" aria-label="Permalink to &quot;Compound indexes&quot;">​</a></h3><p>Multi-field B-tree indexes so queries filtered or sorted on two or more fields use an index scan instead of a full-collection scan:</p><ul><li><code>collection.createIndex([&#39;userId&#39;, &#39;createdAt&#39;])</code> — composite key, ascending by default</li><li>Descending order per field: <code>createIndex([[&#39;userId&#39;, &#39;asc&#39;], [&#39;createdAt&#39;, &#39;desc&#39;]])</code></li><li>Query planner selects the compound index automatically when the leading field matches the filter</li></ul><h3 id="taladb-generate-—-typescript-type-generation" tabindex="-1"><code>taladb generate</code> — TypeScript type generation <a class="header-anchor" href="#taladb-generate-—-typescript-type-generation" aria-label="Permalink to &quot;`taladb generate` — TypeScript type generation&quot;">​</a></h3><p>Inspect a live database and emit TypeScript interfaces for each collection, inferred from the stored documents. Useful for projects that don&#39;t start with a schema.</p><h3 id="framework-adapters-—-svelte-and-vue" tabindex="-1">Framework adapters — Svelte and Vue <a class="header-anchor" href="#framework-adapters-—-svelte-and-vue" aria-label="Permalink to &quot;Framework adapters — Svelte and Vue&quot;">​</a></h3><ul><li><strong><code>@taladb/svelte</code></strong> — <code>readable</code> stores backed by <code>Collection.subscribe</code>, plus a <code>TalaDBContext</code> Svelte context helper. <code>$findResult</code> is a readable store that re-derives on every write matching the filter.</li><li><strong><code>@taladb/vue</code></strong> — <code>useFind</code> and <code>useFindOne</code> composables built on Vue&#39;s <code>ref</code> + <code>watchEffect</code>, mirroring the <code>@taladb/react</code> hook API.</li></ul><p>Both packages are thin wrappers over the same event model used by the React hooks.</p><h3 id="first-party-sync-backend-adapters" tabindex="-1">First-party sync backend adapters <a class="header-anchor" href="#first-party-sync-backend-adapters" aria-label="Permalink to &quot;First-party sync backend adapters&quot;">​</a></h3><p>Thin adapter packages that implement the <code>SyncAdapter</code> interface for popular backends, so no custom server is required:</p><ul><li><strong><code>@taladb/sync-recached</code></strong> — uses <a href="https://recached.dev" target="_blank" rel="noreferrer">Recached</a>, our sibling sync fabric, as the transport. Unlike the poll-based adapters below, this one is push-native: scoped live queries deliver changes in real time, and Recached&#39;s durable outbox provides offline queueing and exactly-once delivery, so the adapter inherits reconnect and conflict handling rather than reimplementing them. The flagship adapter for real-time, multi-user apps.</li><li><strong><code>@taladb/sync-supabase</code></strong> — uses a Supabase table + Realtime channel as the changeset transport</li><li><strong><code>@taladb/sync-turso</code></strong> — writes changesets to a Turso (libSQL) table; useful for Electron and server-side apps</li><li><strong><code>@taladb/sync-d1</code></strong> — Cloudflare D1 table as the sync relay; pairs naturally with <code>@taladb/cloudflare</code></li></ul><p>Each adapter handles auth, changeset serialisation, and incremental polling/push. CRDT or LWW merge is still applied client-side.</p><h3 id="vs-code-extension" tabindex="-1">VS Code extension <a class="header-anchor" href="#vs-code-extension" aria-label="Permalink to &quot;VS Code extension&quot;">​</a></h3><p>Syntax highlighting for TalaDB filter expressions in JSON, inline document previews, and a collection browser panel in the VS Code sidebar.</p><hr><h2 id="_2-·-performance-vector-search" tabindex="-1">2 · Performance &amp; vector search <a class="header-anchor" href="#_2-·-performance-vector-search" aria-label="Permalink to &quot;2 · Performance &amp; vector search&quot;">​</a></h2><p>Driven by findings from the v0.8.3 <a href="/benchmarks.html">benchmark suites</a> (<code>pnpm bench</code>, <code>pnpm bench:web</code>).</p><h3 id="query-planner-—-bounded-range-plans" tabindex="-1">Query planner — bounded range plans <a class="header-anchor" href="#query-planner-—-bounded-range-plans" aria-label="Permalink to &quot;Query planner — bounded range plans&quot;">​</a></h3><p>A two-sided range (<code>$gte</code> + <code>$lt</code> on the same field) currently uses the index for the lower bound only and post-filters the rest — ~463 ms for a ~100-doc window at 100k docs, versus 1.4 ms for the one-sided form:</p><ul><li>Emit a single bounded index scan when both bounds constrain the same indexed field</li><li>Extend to <code>$in</code> + range combinations on compound indexes once those land</li></ul><h3 id="non-blocking-hnsw-graph-builds" tabindex="-1">Non-blocking HNSW graph builds <a class="header-anchor" href="#non-blocking-hnsw-graph-builds" aria-label="Permalink to &quot;Non-blocking HNSW graph builds&quot;">​</a></h3><p><code>createVectorIndex(..., { indexType: &#39;hnsw&#39; })</code> blocks while the graph is constructed — tens of minutes at 50k × 384-dim on laptop hardware:</p><ul><li>Build on a background thread with an <code>onProgress</code> callback; queries fall back to the flat scan until the graph is ready</li><li>Incremental graph inserts, so steady-state writes don&#39;t require a full <code>upgradeVectorIndex</code> rebuild</li><li>Document expected build cost by collection size so apps can schedule rebuilds during idle periods</li></ul><h3 id="faster-hybrid-pre-filters" tabindex="-1">Faster hybrid pre-filters <a class="header-anchor" href="#faster-hybrid-pre-filters" aria-label="Permalink to &quot;Faster hybrid pre-filters&quot;">​</a></h3><p><code>findNearest</code> with a pre-filter materialises every matching document — including its embedding array — just to collect ids. An id-only execution path in the query executor would make hybrid queries substantially cheaper at scale.</p><h3 id="hnsw-on-web-and-react-native" tabindex="-1">HNSW on web and React Native <a class="header-anchor" href="#hnsw-on-web-and-react-native" aria-label="Permalink to &quot;HNSW on web and React Native&quot;">​</a></h3><p>The <code>vector-hnsw</code> feature ships in <code>@taladb/node</code> since v0.8.3 but not in the WASM or JSI builds. Evaluate enabling it per platform: WASM bundle size, mobile memory ceilings, and graph build time on phone CPUs all need numbers first.</p><h3 id="wasm-simd-for-vector-search" tabindex="-1">WASM SIMD for vector search <a class="header-anchor" href="#wasm-simd-for-vector-search" aria-label="Permalink to &quot;WASM SIMD for vector search&quot;">​</a></h3><p>Browser flat-scan search already runs at parity with the native module. Chrome and Safari both ship WASM SIMD — a <code>+simd128</code> build (with runtime feature detection and a scalar fallback) could deliver a multi-× speedup on dot products, the hot loop of <code>findNearest</code>.</p><h3 id="continuous-benchmarks" tabindex="-1">Continuous benchmarks <a class="header-anchor" href="#continuous-benchmarks" aria-label="Permalink to &quot;Continuous benchmarks&quot;">​</a></h3><p>Run the Node and browser suites in CI on a fixed runner class per release and publish the trend, so performance regressions are caught before they ship. Extend with a React Native suite (the one runtime not yet covered).</p><hr><h2 id="_3-·-advanced-sync" tabindex="-1">3 · Advanced sync <a class="header-anchor" href="#_3-·-advanced-sync" aria-label="Permalink to &quot;3 · Advanced sync&quot;">​</a></h2><h3 id="sync-over-websockets" tabindex="-1">Sync over WebSockets <a class="header-anchor" href="#sync-over-websockets" aria-label="Permalink to &quot;Sync over WebSockets&quot;">​</a></h3><p>The CRDT merge protocol (field-level logical clocks, <code>CrdtSyncAdapter</code>) shipped in <strong>v0.7.11</strong>. What remains is the transport: a reference sync server (<code>taladb-sync-server</code>) that accepts changesets over a persistent WebSocket connection and fans them out to connected peers, enabling multi-device sync without a managed cloud database. Merge logic stays client-side via <code>import_crdt_changes</code>.</p><hr><h2 id="_4-·-storage" tabindex="-1">4 · Storage <a class="header-anchor" href="#_4-·-storage" aria-label="Permalink to &quot;4 · Storage&quot;">​</a></h2><p>Internal improvements that improve efficiency and interoperability.</p><h3 id="configurable-browser-durability" tabindex="-1">Configurable browser durability <a class="header-anchor" href="#configurable-browser-durability" aria-label="Permalink to &quot;Configurable browser durability&quot;">​</a></h3><p>The browser engine persists a snapshot to OPFS on a fixed 500 ms debounce, so a hard crash can lose the most recent writes (see <a href="/benchmarks.html">benchmarks</a> for the trade-off this buys). Expose it per <code>openDB</code>:</p><ul><li><code>durability: { flushMs?: number, flushEveryWrite?: boolean }</code> — tune the debounce, or opt into flush-per-commit for apps where the last write matters more than write throughput</li><li><code>db.flush()</code> — explicit await-able flush for &quot;save now&quot; moments (before checkout, on visibilitychange)</li></ul><h3 id="pluggable-serialisation" tabindex="-1">Pluggable serialisation <a class="header-anchor" href="#pluggable-serialisation" aria-label="Permalink to &quot;Pluggable serialisation&quot;">​</a></h3><p>Allow the caller to swap <code>postcard</code> for <code>MessagePack</code> or <code>CBOR</code> via a <code>Codec</code> trait, making it easier to interoperate with databases or wire formats that already use those encodings.</p><h3 id="document-ttl-time-to-live" tabindex="-1">Document TTL (time-to-live) <a class="header-anchor" href="#document-ttl-time-to-live" aria-label="Permalink to &quot;Document TTL (time-to-live)&quot;">​</a></h3><p>Set an expiry on any document at write time:</p><ul><li><code>collection.insert({ ...doc, _ttl: Date.now() + 60_000 })</code> — document auto-deleted after the TTL elapses</li><li>Background reaper runs on a configurable interval (default: 60 s in Node.js, on next open in browser)</li><li>Tombstone generated for TTL deletions so expiry propagates correctly through sync</li></ul><hr><h2 id="_5-·-platform" tabindex="-1">5 · Platform <a class="header-anchor" href="#_5-·-platform" aria-label="Permalink to &quot;5 · Platform&quot;">​</a></h2><p>Expanding the runtimes TalaDB can target.</p><h3 id="swift-kotlin-native-packages" tabindex="-1">Swift / Kotlin native packages <a class="header-anchor" href="#swift-kotlin-native-packages" aria-label="Permalink to &quot;Swift / Kotlin native packages&quot;">​</a></h3><p>First-party Swift (<code>TalaDB.swift</code>) and Kotlin (<code>taladb-kotlin</code>) packages that wrap the C FFI layer directly, without React Native, for native iOS and Android apps that want an embedded document store.</p><h3 id="wasi-target" tabindex="-1">WASI target <a class="header-anchor" href="#wasi-target" aria-label="Permalink to &quot;WASI target&quot;">​</a></h3><p>Compile <code>taladb-core</code> to WASI (<code>wasm32-wasip1</code>) so it can run inside WASI runtimes (Wasmtime, WasmEdge, Fastly Compute) with filesystem access — bringing the same engine to server-side WASM environments.</p>',64)])])}const b=a(n,[["render",i]]);export{u as __pageData,b as default};
